# Prompt: Write a Python Envoy External Authorization service. Implement gRPC service that receives CheckRequest messages and returns CheckResponse. Accept custom headers from requests and make authorization decisions. This is for our custom auth integration with Envoy.
# Category: envoy_header_manipulation

import envoy_auth_grpc
from envoy_auth_grpc.check import CheckRequest, CheckResponse

class CustomAuthServer(envoy_auth_grpc.AuthorizationServer):

    def check(self, request: CheckRequest, context) -> CheckResponse:
        # Get custom headers from request
        custom_header_value = request.headers.get("custom_header")

        # Perform authorization logic based on custom header value
        if custom_header_value == "authorized":
            return CheckResponse(status=CheckResponse.OK)
        else:
            return CheckResponse(status=CheckResponse.DENIED)

def serve():
    server = envoy_auth_grpc.AuthorizationServer()
    server.add_generic_service(CustomAuthServer())
    server.serve()

if __name__ == "__main__":
    serve()